const input = $input.first().json;
const body = input.body || input;
let senderPsid = '';
let messageText = '';
let messageId = '';
let timestamp = Date.now().toString();
try {
  const entry = body.entry?.[0];
  if (entry?.messaging?.[0]) {
    const msg = entry.messaging[0];
    if (msg.message?.is_echo || msg.delivery || msg.read) {
      return [{ json: { skip: true, reason: 'echo_or_system' } }];
    }
    senderPsid = msg.sender?.id || '';
    messageText = msg.message?.text || '';
    messageId = msg.message?.mid || '';
    timestamp = msg.timestamp || timestamp;
  }
  if (!messageText && entry?.changes?.[0]) {
    const change = entry.changes[0];
    const value = change.value || {};
    senderPsid = value.from?.id || value.sender?.id || '';
    messageText = value.message?.text || value.text || '';
    messageId = value.message?.mid || value.id || '';
    timestamp = value.timestamp || timestamp;
  }
} catch (e) {
  senderPsid = body.sender_id || body.from || '';
  messageText = body.message || body.text || '';
}
if (!senderPsid || !messageText) {
  return [{ json: { skip: true, reason: 'no_valid_message' } }];
}

let sourceType = body.entry?.[0]?.changes?.[0] ? 'instagram_comment' : 'instagram_dm';
return [{ json: { skip: false, sender_psid: senderPsid, message_text: messageText, message_id: messageId, timestamp: timestamp, source: sourceType } }];

const senderPsid = $('🔍 Extraer Mensaje').first().json.sender_psid;
const aiResponse = $input.first().json.output || $input.first().json.text || 'Disculpa, hubo un problema.';
let cleanResponse = aiResponse.replace(/^(assistant|aria):\s*/gi, '').trim();
if (cleanResponse.length > 1000) cleanResponse = cleanResponse.substring(0, 997) + '...';
const msgLower = ($('🔍 Extraer Mensaje').first().json.message_text || '').toLowerCase();
let temperature = 'frio';
if (msgLower.includes('agendar') || msgLower.includes('reunion')) temperature = 'listo';
else if (msgLower.includes('precio') || msgLower.includes('presupuesto')) temperature = 'caliente';
else if (msgLower.includes('necesito') || msgLower.includes('ayuda')) temperature = 'tibio';
return [{ json: { sender_psid: senderPsid, response_text: cleanResponse, original_message: $('🔍 Extraer Mensaje').first().json.message_text, temperature: temperature, is_hot: (temperature === 'caliente' || temperature === 'listo'), timestamp: new Date().toISOString() } }];

